if (! function_exists('api_probe')) {
    function api_probe($base_url, $timeout = null, $max_endpoints = null)
    {
        // API Probe — discover the shape of any web API
        $base_url = $base_url ?? '';
        $timeout = $timeout ?? 8;
        $max_endpoints = $max_endpoints ?? 20;

        if (empty($base_url)) {
            return ['error' => 'base_url is required', 'success' => false];
        }

        $timeout = max(2, min(15, (int)$timeout));
        $max_endpoints = max(5, min(40, (int)$max_endpoints));

        // Normalize base URL
        $base_url = rtrim($base_url, '/');

        // Parse it
        $parsed = parse_url($base_url);
        $host = $parsed['host'] ?? '';
        $scheme = $parsed['scheme'] ?? 'https';

        if (empty($host)) {
            return ['error' => 'Could not parse host from URL', 'success' => false];
        }

        // Define probe endpoints — common API paths
        $probe_paths = [
            // Root & health
            '/' => 'Root',
            '/health' => 'Health',
            '/healthz' => 'Healthz',
            '/status' => 'Status',
            '/ping' => 'Ping',
            '/version' => 'Version',
            
            // Common REST patterns
            '/api' => 'API Root',
            '/api/v1' => 'API v1',
            '/api/v2' => 'API v2',
            '/api/v3' => 'API v3',
            '/v1' => 'v1 Root',
            '/v2' => 'v2 Root',
            '/v3' => 'v3 Root',
            
            // Documentation / schema
            '/swagger.json' => 'Swagger JSON',
            '/swagger/v1/swagger.json' => 'Swagger v1',
            '/openapi.json' => 'OpenAPI JSON',
            '/api/docs' => 'API Docs',
            '/docs' => 'Docs',
            '/docs/api' => 'Docs API',
            '/api/documentation' => 'API Documentation',
            '/graphql' => 'GraphQL',
            '/graphiql' => 'GraphiQL',
            
            // Metadata
            '/.well-known' => 'Well Known',
            '/.well-known/openid-configuration' => 'OIDC Config',
            '/favicon.ico' => 'Favicon',
            
            // Common API features
            '/users' => 'Users endpoint',
            '/posts' => 'Posts endpoint',
            '/items' => 'Items endpoint',
            '/data' => 'Data endpoint',
            '/search' => 'Search',
        ];

        // Limit probes
        $probes = array_slice($probe_paths, 0, $max_endpoints, true);

        $results = [];
        $alive_count = 0;
        $detected_type = 'Unknown';
        $detected_formats = [];

        foreach ($probes as $path => $label) {
            $url = $base_url . $path;
            
            $context = stream_context_create([
                'http' => [
                    'method' => 'GET',
                    'timeout' => $timeout,
                    'header' => "User-Agent: api_probe/1.0\r\nAccept: */*\r\n",
                    'ignore_errors' => true,
                    'follow_location' => 1,
                    'max_redirects' => 3,
                ],
                'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
            ]);
            
            $start = microtime(true);
            $body = @file_get_contents($url, false, $context);
            $elapsed_ms = round((microtime(true) - $start) * 1000);
            
            $status_code = 0;
            $content_type = '';
            $content_length = 0;
            $server = '';
            
            if (isset($http_response_header)) {
                foreach ($http_response_header as $h) {
                    if (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) {
                        $status_code = (int)$m[1];
                    } elseif (stripos($h, 'Content-Type:') === 0) {
                        $content_type = trim(substr($h, 13));
                    } elseif (stripos($h, 'Content-Length:') === 0) {
                        $content_length = (int)trim(substr($h, 15));
                    } elseif (stripos($h, 'Server:') === 0) {
                        $server = trim(substr($h, 7));
                    }
                }
                // Reset for next iteration
                unset($http_response_header);
            }
            
            // Determine response category
            $category = 'inaccessible';
            if ($status_code >= 200 && $status_code < 300) {
                $category = 'alive';
                $alive_count++;
            } elseif ($status_code >= 300 && $status_code < 400) {
                $category = 'redirect';
            } elseif ($status_code === 401) {
                $category = 'auth_required';
            } elseif ($status_code === 403) {
                $category = 'forbidden';
            } elseif ($status_code === 404) {
                $category = 'not_found';
            } elseif ($status_code === 405) {
                $category = 'method_not_allowed';
                $alive_count++; // Endpoint exists, wrong method
            } elseif ($status_code >= 500) {
                $category = 'server_error';
            }
            
            // Detect format
            $format = 'unknown';
            if (strpos($content_type, 'application/json') !== false) {
                $format = 'json';
                if (!in_array('JSON', $detected_formats)) $detected_formats[] = 'JSON';
            } elseif (strpos($content_type, 'application/xml') !== false || strpos($content_type, 'text/xml') !== false) {
                $format = 'xml';
                if (!in_array('XML', $detected_formats)) $detected_formats[] = 'XML';
            } elseif (strpos($content_type, 'text/html') !== false) {
                $format = 'html';
                $detected_type = 'Web (HTML)';
            } elseif (strpos($content_type, 'text/plain') !== false) {
                $format = 'text';
            } elseif (strpos($content_type, 'application/graphql') !== false) {
                $format = 'graphql';
                if (!in_array('GraphQL', $detected_formats)) $detected_formats[] = 'GraphQL';
                $detected_type = 'GraphQL';
            }
            
            // Detect GraphQL from response body
            if ($body !== false && !empty($body)) {
                $body_lower = strtolower(mb_substr($body, 0, 1000));
                if (strpos($body_lower, '"data"') !== false && strpos($body_lower, '"query"') !== false) {
                    if ($detected_type === 'Unknown') $detected_type = 'GraphQL';
                }
                if (strpos($body_lower, '"swagger"') !== false || strpos($body_lower, '"openapi"') !== false) {
                    if (!in_array('OpenAPI', $detected_formats)) $detected_formats[] = 'OpenAPI';
                    $detected_type = 'OpenAPI / Swagger';
                }
            }
            
            // Detect REST pattern from status codes across multiple endpoints
            if ($status_code >= 200 && $status_code < 300 && $format === 'json' && $body !== false) {
                $decoded = @json_decode($body, true);
                if ($decoded !== null && is_array($decoded)) {
                    if (!in_array('REST-ish', $detected_formats)) $detected_formats[] = 'REST-ish';
                    if ($detected_type === 'Unknown') $detected_type = 'REST API';
                }
            }
            
            $results[] = [
                'path' => $path,
                'label' => $label,
                'status' => $status_code,
                'category' => $category,
                'content_type' => $content_type ?: 'N/A',
                'response_time_ms' => $elapsed_ms,
                'body_size_bytes' => $body !== false ? strlen($body) : 0,
                'format' => $format,
            ];
        }

        // Determine primary detected type
        if ($detected_type === 'Unknown' && !empty($detected_formats)) {
            if (in_array('JSON', $detected_formats) && in_array('REST-ish', $detected_formats)) {
                $detected_type = 'REST API';
            } elseif (in_array('GraphQL', $detected_formats)) {
                $detected_type = 'GraphQL';
            } elseif (in_array('OpenAPI', $detected_formats)) {
                $detected_type = 'OpenAPI / Swagger';
            } else {
                $detected_type = implode(' + ', $detected_formats);
