        }

        // Summary
        $alive_endpoints = array_filter($results, fn($r) => in_array($r['category'], ['alive', 'method_not_allowed']));
        $auth_endpoints = array_filter($results, fn($r) => $r['category'] === 'auth_required');

        return [
