            'endpoints' => $results,
            'alive_summary' => array_map(fn($r) => $r['path'] . ' → ' . $r['status'] . ' (' . $r['content_type'] . ')', $alive_endpoints),
            'probe_tip' => 'Endpoints marked "alive" or "method_not_allowed" exist. Focus on those for deeper exploration.',
